--
-- Table structure for table `sys_menu`
--

DROP TABLE IF EXISTS `sys_menu`;
CREATE TABLE `sys_menu` (
  `id` varchar(27) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键ID（KSUID）',
  `pid` varchar(27) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '父菜单ID，顶级菜单为NULL',
  `name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '菜单/按钮名称',
  `code` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '菜单/按钮编码，用于权限控制',
  `type` tinyint(4) NOT NULL COMMENT '菜单类型：1=menu, 2=catalog, 3=button, 4=embedded, 5=link',
  `status` tinyint(4) NOT NULL DEFAULT '1' COMMENT '状态：1启用，0禁用',
  `path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '前端路由路径',
  `active_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '激活路径',
  `component` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '前端组件路径',
  `icon` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '菜单/按钮图标',
  `meta_active_icon` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '激活状态图标',
  `meta_title` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '前端显示标题，可用于国际化',
  `meta_order` int(11) DEFAULT '0' COMMENT '菜单排序，数值越小越靠前',
  `meta_affix_tab` tinyint(1) DEFAULT '0' COMMENT '是否固定标签页',
  `meta_keep_alive` tinyint(1) DEFAULT '0' COMMENT '是否保持组件活跃状态',
  `meta_hide_in_menu` tinyint(1) DEFAULT '0' COMMENT '是否在菜单中隐藏',
  `meta_hide_children_in_menu` tinyint(1) DEFAULT '0' COMMENT '是否隐藏子菜单',
  `meta_hide_in_breadcrumb` tinyint(1) DEFAULT '0' COMMENT '是否在面包屑中隐藏',
  `meta_hide_in_tab` tinyint(1) DEFAULT '0' COMMENT '是否在标签页中隐藏',
  `meta_badge` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '徽标显示内容',
  `meta_badge_type` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '徽标类型，如 normal/dot',
  `meta_badge_variants` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '徽标颜色或样式',
  `meta_iframe_src` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '内嵌 IFrame 链接',
  `meta_link` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '外部链接地址',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `created_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人名字',
  `created_at` timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `updated_by` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人名字',
  `updated_at` timestamp(6) NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6) COMMENT '更新时间',
  `created_id` varchar(27) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '创建人ID',
  `updated_id` varchar(27) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '更新人ID',
  `is_deleted` tinyint(1) NOT NULL DEFAULT '0' COMMENT '逻辑删除标记：false=未删除，true=已删除',
  PRIMARY KEY (`id`),
  KEY `idx_sys_menu_pid` (`pid`),
  KEY `idx_sys_menu_type` (`type`),
  KEY `idx_sys_menu_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='系统菜单表（支持多级菜单和按钮权限）';

--
-- Data for table `sys_menu`
--

